let impact = "low";

if ($input.first().json.urgency === "critical") impact = "high";
else if ($input.first().json.urgency === "high") impact = "medium";

return [{ ...$input, impact }];

let priority, sla_minutes, priority_label;

if ($('When Executed by Another Workflow').first().json.urgency === "critical" && $input.first().json.impact === "high") {
  priority = 1;
  sla_minutes = 15;
  priority_label = "P1 - Critical";
} else if ($('When Executed by Another Workflow').first().json.urgency === "high") {
  priority = 2;
  sla_minutes = 60;
  priority_label = "P2 - High";
} else if ($('When Executed by Another Workflow').first().json.urgency === "medium") {
  priority = 3;
  sla_minutes = 240;
  priority_label = "P3 - Medium";
} else {
  priority = 4;
  sla_minutes = 1440;
  priority_label = "P4 - Low";
}

return [{ ...$input, priority, sla_minutes, priority_label }];

const original = $('Calculate Impact').first().json.item.json;
const content = $input.first().json.choices[0].message.content;

let parsed;

try {
  parsed = JSON.parse(content);
} catch (error) {
  parsed = {
    error: "Invalid JSON",
    raw: content
  };
}

return [{
  ...original, 
  ...parsed     
}];
